"""Tests for the hash chaining module."""

import pytest
from audit.hasher import compute_entry_hash, verify_chain


class TestHasher:
    def test_compute_hash_returns_hex(self):
        entry = {"transaction_id": "txn-001", "amount_cents": 1000}
        h = compute_entry_hash(entry)
        assert isinstance(h, str)
        assert len(h) == 64

    def test_hash_chain_links(self):
        e1 = {"transaction_id": "txn-001", "amount_cents": 1000}
        h1 = compute_entry_hash(e1)
        e2 = {"transaction_id": "txn-002", "amount_cents": 2000}
        h2 = compute_entry_hash(e2, previous_hash=h1)
        assert h1 != h2

    def test_verify_chain_valid(self):
        entries = []
        prev = None
        for i in range(3):
            e = {"transaction_id": f"txn-{i}", "amount_cents": (i + 1) * 100}
            h = compute_entry_hash(e, prev)
            e["entry_hash"] = h
            e["previous_hash"] = prev
            entries.append(e)
            prev = h
        assert verify_chain(entries) is True

    def test_verify_chain_tampered(self):
        entries = []
        prev = None
        for i in range(3):
            e = {"transaction_id": f"txn-{i}", "amount_cents": (i + 1) * 100}
            h = compute_entry_hash(e, prev)
            e["entry_hash"] = h
            e["previous_hash"] = prev
            entries.append(e)
            prev = h
        # Tamper with middle entry
        entries[1]["amount_cents"] = 99999
        assert verify_chain(entries) is False

    def test_deterministic_hashing(self):
        entry = {"transaction_id": "txn-001", "amount_cents": 500}
        h1 = compute_entry_hash(entry)
        h2 = compute_entry_hash(entry)
        assert h1 == h2
